1	export type Cell = [x: number, y: number];
2	
3	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
4	
5	const neighborsOf = ([x, y]: Cell): Cell[] => {
6	  const neighbors: Cell[] = [];
7	  for (let dx = -1; dx <= 1; dx++) {
8	    for (let dy = -1; dy <= 1; dy++) {
9	      if (dx === 0 && dy === 0) continue;
10	      neighbors.push([x + dx, y + dy]);
11	    }
12	  }
13	  return neighbors;
14	};
15	
16	const willBeAlive = (isCurrentlyAlive: boolean, liveNeighbors: number): boolean =>
17	  isCurrentlyAlive
18	    ? liveNeighbors === 2 || liveNeighbors === 3
19	    : liveNeighbors === 3;
20	
21	export const nextGeneration = (cells: Cell[]): Cell[] => {
22	  const liveCells = new Set(cells.map(cellKey));
23	
24	  const countLiveNeighbors = (cell: Cell): number =>
25	    neighborsOf(cell).filter((n) => liveCells.has(cellKey(n))).length;
26	
27	  const candidates = new Map<string, Cell>();
28	  for (const cell of cells) {
29	    for (const candidate of [cell, ...neighborsOf(cell)]) {
30	      candidates.set(cellKey(candidate), candidate);
31	    }
32	  }
33	
34	  const result: Cell[] = [];
35	  for (const [key, cell] of candidates) {
36	    if (willBeAlive(liveCells.has(key), countLiveNeighbors(cell))) {
37	      result.push(cell);
38	    }
39	  }
40	  return result;
41	};
