1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("returns empty array when given empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("returns empty array when a single live cell has no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("returns empty array when two adjacent cells each have only 1 neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 0], [1, 0]])).toEqual([]);
13	  });
14	  it("keeps a block (still life) unchanged - 4 cells each with 3 neighbors survive", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    expect(nextGeneration(block).sort()).toEqual(block.sort());
17	  });
18	  it("transforms a vertical blinker to a horizontal blinker (oscillator)", () => {
19	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
20	    const horizontal: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
21	    expect(nextGeneration(vertical).sort()).toEqual(horizontal.sort());
22	  });
23	  it("creates a new live cell when a dead cell has exactly 3 live neighbors (reproduction)", () => {
24	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1]];
25	    const expected: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
26	    expect(nextGeneration(input).sort()).toEqual(expected.sort());
27	  });
28	  it("kills a live cell with more than 3 live neighbors (overpopulation)", () => {
29	    // Center (1,1) plus its 4 orthogonal neighbors: center has 4 neighbors → dies
30	    const input: [number, number][] = [[1, 1], [0, 1], [2, 1], [1, 0], [1, 2]];
31	    const result = nextGeneration(input);
32	    expect(result).not.toContainEqual([1, 1]);
33	  });
34	  it.todo("handles negative coordinates correctly");
35	});
